insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:c7e8c71e', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "‘una dieta equilibrada’ means…", "options": ["a balanced diet", "a varied menu", "a healthy lifestyle", "a strict weight-loss plan"]}'::jsonb, '{"answer": 0, "explain": "equilibrada = balanced. ‘variada’ (varied), ‘vida sana’ (lifestyle) and a diet-plan are close but wrong."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:9b8e8f18', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "Only ONE sentence is fully correct. Which?", "options": ["Me gustan las verduras", "Me gusta las verduras", "A mí me gusta mucho las verduras", "Yo gusto las verduras todos los días"]}'::jsonb, '{"answer": 0, "explain": "The thing liked is plural (verduras) so the verb is gustan. B fails to agree; C still uses gusta with a plural; D wrongly conjugates gustar as ‘yo gusto’."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:5900359d', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "How do you say ‘I am going to eat more vegetables’?", "options": ["Voy a comer más verduras", "Como muchas más verduras ahora", "Se debe comer más verduras hoy", "Voy comer más verduras cada día"]}'::jsonb, '{"answer": 0, "explain": "A plan = voy a + infinitive. B is present tense; C is impersonal advice; D drops the ‘a’ that ‘voy a’ needs."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:e4486e27', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "In ‘Voy a evitar la comida rápida’, ‘evitar’ means to…", "options": ["avoid", "prepare it quickly", "cut down on it", "order it less often"]}'::jsonb, '{"answer": 0, "explain": "evitar = to avoid. The longer options are tempting ‘sort of healthy’ ideas, but none means avoid."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:de4e53f3', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "‘Bebo mucha ___.’ — which word fits BOTH the grammar and ‘I drink lots of water’?", "options": ["agua", "leche", "zumo", "café con leche"]}'::jsonb, '{"answer": 0, "explain": "‘mucha’ is feminine, so leche/agua both fit grammatically — but only ‘agua’ = water. zumo is masculine (mucho zumo)."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:fb6c2008', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "Which word means ‘because’ (gives a reason)?", "options": ["porque", "aunque", "también", "pero"]}'::jsonb, '{"answer": 0, "explain": "porque = because. ‘aunque’ (although) is the closest trap; también = also; pero = but."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:c271de74', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "Why is ‘Se debería reducir el azúcar’ a strong Higher-tier phrase?", "options": ["It uses the conditional", "It is in the present tense", "It gives a direct command", "It describes a completed past action"]}'::jsonb, '{"answer": 0, "explain": "‘se debería’ = one should (conditional) — a Higher feature. The traps name other tenses/moods of similar length."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:6b29a999', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "What is true about ‘vegano’ and ‘vegetariano’?", "options": ["vegano is stricter than vegetariano", "vegetariano never eats cheese, eggs or milk, only vegano does", "vegano and vegetariano are just two spellings of the same word", "vegetariano is the stricter of the two and avoids all animal products"]}'::jsonb, '{"answer": 0, "explain": "A vegano avoids ALL animal products; a vegetariano may still eat cheese, eggs or milk — the traps swap which one is stricter or claim they are synonyms."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:4c62f307', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "‘un régimen (alimenticio)’ is another way of saying…", "options": ["a diet", "a military base", "a type of exercise", "a medical prescription"]}'::jsonb, '{"answer": 0, "explain": "régimen (alimenticio) = an eating regime/diet. The distractors are false-friend guesses from ‘régimen’ sounding like ‘regiment’ or ‘regimen’ in English."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:466c9613', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "‘el sobrepeso’ means…", "options": ["being overweight", "losing weight quickly", "having a big appetite", "feeling very hungry"]}'::jsonb, '{"answer": 0, "explain": "el sobrepeso = being overweight (sobre = over + peso = weight). It is a state, not an action like losing weight or a feeling like hunger."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:52c2f355', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "‘una reacción alérgica a un alimento’ means…", "options": ["an allergic reaction to a food", "a strong preference for a food", "a diet based around one food", "a recipe using a rare food"]}'::jsonb, '{"answer": 0, "explain": "reacción alérgica = allergic reaction; alimento = food. The traps reinterpret ‘reacción’ as a preference or turn ‘alimento’ into a recipe/diet."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:9a84a5f4', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "Which sentence gives good advice about ‘el consumo de azúcar’?", "options": ["Se debe reducir el consumo de azúcar", "Se debe aumentar el consumo de azúcar todos los días", "No importa cuánto azúcar consumas", "El consumo de azúcar no afecta a la salud"]}'::jsonb, '{"answer": 0, "explain": "Good advice = reduce sugar consumption. The traps tell you to increase it, ignore it, or claim it has no effect on health."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:4c74923c', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "‘Quiero disfrutar de la comida’ means…", "options": ["I want to enjoy the food", "I want to finish the food quickly", "I want to share the food with everyone", "I want to complain about the food"]}'::jsonb, '{"answer": 0, "explain": "disfrutar (de) = to enjoy. The traps invent a rush, a share-out or a complaint that was never mentioned."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:mcq:7ae2db76', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'mcq', 'mcq', 1, '{"question": "‘¿Te atreves a probar algo nuevo?’ asks…", "options": ["Whether you dare to try something new", "Whether you have already tried something new", "Whether you like trying new restaurants", "Whether you are afraid of new food"]}'::jsonb, '{"answer": 0, "explain": "atreverse a = to dare to. The traps shift it to the past, to restaurants, or reverse it into fear."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:2a8da2c8', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘una dieta equilibrada’ means ‘a balanced diet’."}'::jsonb, '{"answer": true, "explain": "equilibrada = balanced."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:74faf293', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘se debe’ is followed by a past-tense verb."}'::jsonb, '{"answer": false, "explain": "It is followed by an infinitive: se debe comer / beber / evitar."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:43912343', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘Me gustan las verduras’ is correct because ‘verduras’ is plural."}'::jsonb, '{"answer": true, "explain": "gustar agrees with the thing liked; plural → gustan."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:2e56aa3c', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘evitar’ means ‘to enjoy’."}'::jsonb, '{"answer": false, "explain": "evitar = to avoid."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:41c7f9b4', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘voy a comer’ describes a future plan."}'::jsonb, '{"answer": true, "explain": "voy a + infinitive = near future."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:525ee299', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘el azúcar’ means ‘salt’."}'::jsonb, '{"answer": false, "explain": "el azúcar = sugar; salt = la sal."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:db7ffd90', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘porque’ means ‘but’."}'::jsonb, '{"answer": false, "explain": "porque = because; ‘but’ = pero."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:8b81b721', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘Se debería reducir el azúcar’ uses the conditional and suits Higher tier."}'::jsonb, '{"answer": true, "explain": "se debería = one should (conditional)."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:c0408539', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘vegetariano’ and ‘vegano’ mean exactly the same thing."}'::jsonb, '{"answer": false, "explain": "A vegano avoids all animal products; a vegetariano may still eat eggs, cheese or milk."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:3fe172d3', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘el consumo de azúcar’ means ‘sugar consumption’."}'::jsonb, '{"answer": true, "explain": "consumo = consumption."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:cbbf8b0a', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘tener sed’ means ‘to be hungry’."}'::jsonb, '{"answer": false, "explain": "tener sed = to be thirsty; tener hambre = to be hungry."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:ac40a615', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘permitirse un capricho’ means ‘to allow yourself a treat’."}'::jsonb, '{"answer": true, "explain": "permitirse = to allow oneself; un capricho = a treat/indulgence."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:329f119c', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘acompañar la carne con verduras’ means to serve meat with vegetables."}'::jsonb, '{"answer": true, "explain": "acompañar = to accompany/go with — the vegetables are served alongside the meat."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tf:b80631b3', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tf', 'tf', 1, '{"question": "‘Me alegro de comer sano’ means ‘I regret eating healthily’."}'::jsonb, '{"answer": false, "explain": "alegrarse (de) = to be glad (about); it means being glad to eat healthily, not regretting it."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:learn:83731027', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'learn', 'mcq', 1, '{"readingTitle": "What food and drink words do I need?", "reading": "<p>Start with the core nouns for <strong>la comida</strong> (food) and <strong>la bebida</strong> (drink). Every Spanish word below is on the AQA list — tap 🔊 to hear it.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"la fruta\">la fruta</span></td><td>fruit</td><td><span data-say=\"las verduras\">las verduras</span></td><td>vegetables</td></tr>\n              <tr><td><span data-say=\"la carne\">la carne</span></td><td>meat</td><td><span data-say=\"el pescado\">el pescado</span></td><td>fish</td></tr>\n              <tr><td><span data-say=\"el pan\">el pan</span></td><td>bread</td><td><span data-say=\"el queso\">el queso</span></td><td>cheese</td></tr>\n              <tr><td><span data-say=\"el agua\">el agua</span></td><td>water</td><td><span data-say=\"la leche\">la leche</span></td><td>milk</td></tr>\n              <tr><td><span data-say=\"el azúcar\">el azúcar</span></td><td>sugar</td><td><span data-say=\"la grasa\">la grasa</span></td><td>fat</td></tr>\n            </table>\n            <p>Two useful meal words: <span data-say=\"el desayuno\">el desayuno</span> (breakfast) and <span data-say=\"la cena\">la cena</span> (dinner).</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el alimento\">el alimento</span></td><td>food(stuff)</td><td><span data-say=\"el vaso\">el vaso</span></td><td>glass</td></tr>\n              <tr><td><span data-say=\"la botella\">la botella</span></td><td>bottle</td><td><span data-say=\"la sed\">la sed</span></td><td>thirst</td></tr>\n              <tr><td><span data-say=\"vegetariano\">vegetariano / vegetariana</span></td><td>vegetarian</td><td><span data-say=\"vegano\">vegano / vegana</span></td><td>vegan</td></tr>\n            </table>\n            <p>Two more useful words: <span data-say=\"el diente\">el diente</span> (tooth) — <span data-say=\"El azúcar es malo para los dientes.\">El azúcar es malo para los dientes.</span> (Sugar is bad for your teeth) — and <span data-say=\"tener sed\">tener sed</span> (to be thirsty): <span data-say=\"Cuando tengo sed, bebo un vaso de agua.\">Cuando tengo sed, bebo un vaso de agua.</span></p>\n            <p>When we eat out, everyone often has to <span data-say=\"traer\">traer</span> something — <span data-say=\"Voy a traer una ensalada a la fiesta.\">Voy a traer una ensalada a la fiesta.</span> (I''m going to bring a salad to the party.) It''s also important to <span data-say=\"incluir\">incluir</span> vegetables in every meal: <span data-say=\"Intento incluir verduras en cada comida.\">Intento incluir verduras en cada comida.</span> (I try to include vegetables in every meal.)</p>", "question": "Which pair means ‘fruit and vegetables’?", "options": ["la fruta y las verduras", "las legumbres y el pescado", "la carne y el queso", "el agua y la leche"]}'::jsonb, '{"answer": 0, "explain": "la fruta = fruit, las verduras = vegetables. B mixes pulses and fish; C is meat and cheese."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:learn:18817afb', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'learn', 'mcq', 1, '{"readingTitle": "How do I describe a balanced diet?", "reading": "<p>The headline phrase is <span data-say=\"una dieta equilibrada\">una dieta equilibrada</span> — <em>a balanced diet</em>. Notice the adjective <strong>equilibrada</strong> agrees with the feminine noun <strong>dieta</strong>.</p>\n            <ul>\n              <li><span data-say=\"sano\">sano</span> / <span data-say=\"saludable\">saludable</span> = healthy</li>\n              <li><span data-say=\"bueno para la salud\">bueno para la salud</span> = good for your health</li>\n              <li><span data-say=\"malo para la salud\">malo para la salud</span> = bad for your health</li>\n            </ul>\n            <p>Model sentence: <span data-say=\"Como una dieta equilibrada porque es buena para la salud.\">Como una dieta equilibrada porque es buena para la salud.</span> — <em>I eat a balanced diet because it is good for your health.</em></p>\n            <p>We can also talk about <span data-say=\"nuestra dieta\">nuestra dieta</span> (our diet), and use <span data-say=\"un régimen alimenticio\">un régimen (alimenticio)</span> — <em>a diet / eating regime</em> — as another way to say “diet”. <span data-say=\"Seguir un régimen puede ser complicado al principio.\">Seguir un régimen puede ser complicado al principio.</span> — <em>Following a diet/regime can be complicated at first.</em></p>\n            <p>Doctors recommend reducing <span data-say=\"el consumo de azúcar\">el consumo de azúcar</span> (sugar consumption), because too much can lead to <span data-say=\"el sobrepeso\">el sobrepeso</span> (being overweight). <span data-say=\"Dentro de una dieta equilibrada, se puede comer un poco de chocolate.\">Dentro de una dieta equilibrada, se puede comer un poco de chocolate.</span> — <em>Within a balanced diet, you can eat a little chocolate.</em></p>\n            <p>Before buying, it''s a good idea to <span data-say=\"mirar la etiqueta\">mirar la etiqueta</span> (look at the label) to see how much sugar it contains. Within a balanced diet, <span data-say=\"te puedes permitir un capricho de vez en cuando\">te puedes permitir un capricho de vez en cuando</span> — <em>you can allow yourself a treat now and then.</em></p>", "question": "Why does ‘equilibrada’ end in ‑a?", "options": ["It agrees with the feminine noun ‘dieta’", "It must copy the last letter of the word before it", "It is a verb ending", "It marks the plural"]}'::jsonb, '{"answer": 0, "explain": "Adjectives agree in gender and number with their noun: dieta is feminine singular → equilibrada (not a rule about the previous word)."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:learn:00ad8521', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'learn', 'mcq', 1, '{"readingTitle": "How do I give advice? (se debe / hay que)", "reading": "<p>To say what people <strong>should</strong> do, use these impersonal structures — each is followed by an <strong>infinitive</strong>:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"se debe\">se debe…</span></td><td>one must / you should…</td></tr>\n              <tr><td><span data-say=\"no se debe\">no se debe…</span></td><td>one must not…</td></tr>\n              <tr><td><span data-say=\"hay que\">hay que…</span></td><td>you have to…</td></tr>\n            </table>\n            <p>Examples:</p>\n            <ul>\n              <li><span data-say=\"Se debe comer más fruta.\">Se debe comer más fruta.</span> — One should eat more fruit.</li>\n              <li><span data-say=\"No se debe comer demasiada grasa.\">No se debe comer demasiada grasa.</span> — One must not eat too much fat.</li>\n              <li><span data-say=\"Hay que beber mucha agua.\">Hay que beber mucha agua.</span> — You have to drink lots of water.</li>\n            </ul>\n            <p>Advice often mentions a <span data-say=\"el límite\">el límite</span> (limit): <span data-say=\"Hay un límite de azúcar recomendado al día.\">Hay un límite de azúcar recomendado al día.</span> — <em>There is a recommended sugar limit per day.</em> Some people have <span data-say=\"una reacción alérgica\">una reacción alérgica</span> (an allergic reaction) to certain foods, so it is important to check the label.</p>", "question": "What kind of word follows ‘se debe’, ‘no se debe’ and ‘hay que’?", "options": ["an infinitive verb", "a fully conjugated past-tense verb", "a plural noun", "an adjective"]}'::jsonb, '{"answer": 0, "explain": "All three advice structures are followed by an infinitive (comer, beber, evitar…), never a conjugated form."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:learn:ecc836f7', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'learn', 'mcq', 1, '{"readingTitle": "How do I say what I am going to change?", "reading": "<p>Use the near future — <strong>voy a</strong> + <strong>infinitive</strong> — to state a plan or intention:</p>\n            <ul>\n              <li><span data-say=\"Voy a comer más verduras.\">Voy a comer más verduras.</span> — I am going to eat more vegetables.</li>\n              <li><span data-say=\"Voy a evitar la comida rápida.\">Voy a evitar la comida rápida.</span> — I am going to avoid fast food.</li>\n              <li><span data-say=\"Voy a beber menos azúcar.\">Voy a beber menos azúcar.</span> — I am going to have less sugar.</li>\n            </ul>\n            <p><strong>evitar</strong> = to avoid, <strong>la comida rápida</strong> = fast food. Add a time phrase to extend: <span data-say=\"todos los días\">todos los días</span> (every day), <span data-say=\"a menudo\">a menudo</span> (often).</p>\n            <p>You can add a month too: <span data-say=\"en mayo\">en mayo</span> (in May), <span data-say=\"en julio\">en julio</span> (in July), <span data-say=\"en noviembre\">en noviembre</span> (in November) — for example: <span data-say=\"En julio como mucha fruta de temporada, pero en noviembre como más sopa.\">En julio como mucha fruta de temporada, pero en noviembre como más sopa.</span> — <em>In July I eat a lot of seasonal fruit, but in November I eat more soup.</em> <span data-say=\"Probablemente voy a comer menos azúcar el año que viene.\">Probablemente voy a comer menos azúcar el año que viene.</span> — <em>I am probably going to eat less sugar next year.</em></p>", "question": "How do you say ‘I am going to avoid fast food’?", "options": ["Voy a evitar la comida rápida", "Se debe evitar la comida rápida", "Evito la comida rápida", "Hay que evitar la comida rápida"]}'::jsonb, '{"answer": 0, "explain": "voy a + infinitive = a future plan; ‘I am going to avoid’ = Voy a evitar."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:learn:3933554d', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'learn', 'mcq', 1, '{"readingTitle": "How do I give opinions and reasons?", "reading": "<p>Opinions lift your mark. Use <strong>gustar</strong>-type verbs and join ideas with connectors:</p>\n            <ul>\n              <li><span data-say=\"Me gusta la fruta.\">Me gusta la fruta.</span> — I like fruit. <em>(singular thing)</em></li>\n              <li><span data-say=\"Me gustan las verduras.\">Me gustan las verduras.</span> — I like vegetables. <em>(plural → gusta<strong>n</strong>)</em></li>\n              <li><span data-say=\"Prefiero el pescado.\">Prefiero el pescado.</span> — I prefer fish.</li>\n            </ul>\n            <p>Connectors: <span data-say=\"porque\">porque</span> (because), <span data-say=\"pero\">pero</span> (but), <span data-say=\"también\">también</span> (also). Example: <span data-say=\"Me gusta la carne, pero no como carne todos los días porque es mala para la salud.\">Me gusta la carne, pero no como carne todos los días porque es mala para la salud.</span></p>\n            <p><span data-say=\"Es extraño, pero no me gusta la fruta.\">Es extraño, pero no me gusta la fruta.</span> — <em>It’s strange, but I don’t like fruit.</em> In some <span data-say=\"casos\">casos</span> (cases), people prefer <span data-say=\"el segundo plato\">el segundo plato</span> (the second course) to the first. <span data-say=\"En la comida anterior comí demasiada grasa, así que hoy prefiero algo más ligero.\">En la comida anterior comí demasiada grasa, así que hoy prefiero algo más ligero.</span> — <em>In the previous meal I ate too much fat, so today I prefer something lighter.</em></p>\n            <p>I also like to <span data-say=\"acompañar la carne con verduras\">acompañar la carne con verduras</span> — <em>accompany meat with vegetables</em> — and above all I want to <span data-say=\"disfrutar de la comida\">disfrutar de la comida</span> — <em>enjoy the food</em> — instead of eating in a rush.</p>", "question": "Why is it ‘Me gustan las verduras’ (not ‘gusta’)?", "options": ["verduras is plural, so the verb agrees", "it expresses a future plan, not a preference", "verduras is a feminine singular noun here", "it is simply someone’s opinion"]}'::jsonb, '{"answer": 0, "explain": "gustar agrees with the THING liked; verduras is plural → gustan (nothing to do with plans or opinions)."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:learn:0e35c440', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'learn', 'mcq', 1, '{"readingTitle": "Higher: reach for the top band", "reading": "<p><span class=\"tier-h\">H</span> To push into the higher band, add a <strong>conditional</strong> recommendation and a <strong>concession</strong>:</p>\n            <ul>\n              <li><span data-say=\"Se debería reducir el azúcar.\">Se debería reducir el azúcar.</span> — One <em>should</em> reduce sugar. <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Lo más importante es llevar una dieta variada.\">Lo más importante es llevar una dieta variada.</span> — The most important thing is to have a varied diet. <span class=\"tier-h\">H</span></li>\n              <li><span data-say=\"Aunque me gusta el chocolate, intento comer sano.\">Aunque me gusta el chocolate, intento comer sano.</span> — Although I like chocolate, I try to eat healthily. <span class=\"tier-h\">H</span></li>\n            </ul>\n            <p>Aim for: <strong>opinion + reason + connector + a second tense</strong> in one sentence.</p>\n            <p><span class=\"tier-h\">H</span> Compare people’s diets: <span data-say=\"Mi dieta es vegetariana; la suya es vegana.\">Mi dieta es vegetariana; la suya es vegana.</span> — <em>My diet is vegetarian; theirs/his/hers is vegan.</em> <span data-say=\"Claro, cada persona tiene su propia opinión.\">Claro, cada persona tiene su propia opinión.</span> — <em>Of course, everyone has their own opinion.</em> <span data-say=\"Desde mi juventud, intento comer sano, y el aceite de oliva es el tercer ingrediente más importante de mi dieta.\">Desde mi juventud, intento comer sano, y el aceite de oliva es el tercer ingrediente más importante de mi dieta.</span> — <em>Since my youth, I have tried to eat healthily, and olive oil is the third most important ingredient in my diet.</em> <span class=\"tier-h\">H</span></p>\n            <p><span class=\"tier-h\">H</span> <span data-say=\"¿Te atreves a probar algo nuevo?\">¿Te atreves a probar algo nuevo?</span> — <em>Do you dare to try something new?</em> And I''m always <span data-say=\"me alegro de comer sano\">me alegro de comer sano</span> — <em>glad to eat healthily.</em> <span class=\"tier-h\">H</span></p>", "question": "Which sentence shows a typically Higher-tier feature?", "options": ["Se debería reducir el azúcar", "Me gusta mucho la fruta fresca del país", "Como pan casi todos los días", "Bebo bastante agua con las comidas"]}'::jsonb, '{"answer": 0, "explain": "‘se debería’ is a conditional — a Higher feature. Option B is longer but only present-tense opinion."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:misc:d583c1b6', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Me gusta las verduras.</p><p><strong>✅ The correct idea:</strong> Me gustan las verduras.</p>", "question": "Why is it ‘Me gustan las verduras’?", "options": ["verduras is plural, so it becomes gustan", "the subject ‘yo’ is what forces the ending gustan here", "verduras is a masculine noun", "the sentence is in the past"]}'::jsonb, '{"answer": 0, "explain": "gustar agrees with the thing liked (verduras, plural) → gustan. It is NOT the person that drives the ending — that is the classic error."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:misc:230b261d', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> una dieta equilibrado</p><p><strong>✅ The correct idea:</strong> una dieta equilibrada</p>", "question": "Why must it be ‘equilibrada’?", "options": ["the adjective agrees with the feminine noun ‘dieta’", "it copies the gender of whichever verb happens to be closest to it", "the masculine form is the safe default", "adjectives only change in the plural"]}'::jsonb, '{"answer": 0, "explain": "Adjectives agree with their noun in gender AND number: dieta is feminine singular → equilibrada."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:misc:e780eb6d', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Se debe comí más fruta.</p><p><strong>✅ The correct idea:</strong> Se debe comer más fruta.</p>", "question": "What must follow ‘se debe’?", "options": ["an infinitive (comer)", "a verb written in a past tense form", "a plural noun", "an adjective"]}'::jsonb, '{"answer": 0, "explain": "‘se debe’ always takes an infinitive, never a conjugated past form."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:misc:2dd656d0', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Voy comer más verduras.</p><p><strong>✅ The correct idea:</strong> Voy a comer más verduras.</p>", "question": "What is missing in ‘Voy comer…’?", "options": ["the linking word ‘a’ (voy a + infinitive)", "an accent on the final vowel of the infinitive comer", "the pronoun ‘me’", "the article ‘las’"]}'::jsonb, '{"answer": 0, "explain": "The near future is voy/vas/va + a + infinitive; the ‘a’ is compulsory."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:misc:b0a42276', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Como comida sensible.</p><p><strong>✅ The correct idea:</strong> Como comida sana.</p>", "question": "Why is ‘sensible’ wrong here for ‘healthy’?", "options": ["it is a false friend meaning ‘sensitive’", "it is the plural of an adjective you can’t use", "it is a verb, not an adjective", "it simply needs a written accent"]}'::jsonb, '{"answer": 0, "explain": "False friend: Spanish ‘sensible’ = sensitive. Healthy = sano/sana/saludable."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:misc:411b3870', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Soy vegano, como queso y huevos.</p><p><strong>✅ The correct idea:</strong> Soy vegetariano, como queso y huevos. (Un vegano no come queso, huevos ni ningún otro producto animal.)</p>", "question": "Why is ‘Soy vegano, como queso y huevos’ a contradiction?", "options": ["a vegano eats no animal products at all, including cheese and eggs", "vegano and vegetariano are simply two different spellings of one word, so they mean exactly the same thing", "cheese and eggs are not animal products", "vegano only refers to not eating meat, cheese is always fine"]}'::jsonb, '{"answer": 0, "explain": "vegano = vegan (zero animal products, including dairy and eggs); vegetariano can still eat cheese and eggs — the two words are not interchangeable."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tips:98ed37b5', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Dictation (listening)", "reading": "In the dictation you hear short sentences and write them down. Listen for whole chunks you know (‘se debe comer…’, ‘voy a…’) rather than single sounds. Get the accents where you can, but a minor accent slip is not always penalised — spelling the word right matters most.", "question": "What is the best dictation strategy?", "options": ["Write the whole chunks you recognise, not single sounds", "Write down each and every individual letter that you hear", "Only ever write the very first word of each sentence", "Translate it straight into English as you listen"]}'::jsonb, '{"answer": 0, "explain": "You already know whole phrases (‘se debe comer’, ‘voy a…’); catching them as chunks is far more reliable than letter-by-letter."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tips:e8b76005', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 3 — Translation into English", "reading": "Don’t translate word-for-word. ‘Se debe comer fruta’ is ‘One should / you should eat fruit’, not ‘It must to eat fruit’. Keep the tense: ‘voy a evitar’ = ‘I am going to avoid’.", "question": "‘Voy a evitar la comida rápida’ means…", "options": ["I am going to avoid fast food", "I am not going to avoid fast food", "I used to avoid fast food a lot", "I have already avoided fast food"]}'::jsonb, '{"answer": 0, "explain": "voy a + infinitive = the near future. The traps flip the meaning to a negative or a different tense — all longer than the answer."}'::jsonb),
('spanish:2-1-food-drink-and-a-balanced-diet:tips:9a528c5f', 'spanish', 'spanish:2-1-food-drink-and-a-balanced-diet', '2.1 Food, Drink and a Balanced Diet', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Paper 4 — Writing & translation into Spanish", "reading": "For top marks combine an opinion, a reason and a second tense in one sentence: ‘Me gusta la carne, pero voy a comer menos porque es mala para la salud.’ At Higher, add ‘se debería…’ or ‘aunque…’.", "question": "Which sentence would score highest?", "options": ["Me gusta la carne, pero voy a comer menos porque es mala para la salud", "A mí me gusta mucho la carne y como carne y la carne está muy rica siempre", "Me gusta la carne", "Como carne todos los días"]}'::jsonb, '{"answer": 0, "explain": "The winner combines an opinion, a connector, a second tense (future) AND a reason. Option B is even longer but just repeats one idea in the present — length alone is not what scores."}'::jsonb),
